<template>
  <div>
    <div style="width: 100%; height: 60px; background-color: #fff; padding: 0px 12px;" v-if="!loading || data.ratedContestantsCount !== 0">
      <p style="font-size: 22px; margin-bottom: 0; text-align: center;">{{ data.judgeName }}</p>
      <p style="font-size: 16px; margin-bottom: 0; text-align: center;">已评{{ data.ratedContestantsCount }}位选手<span v-if="data.ratedContestantsCount !== 0">，平均打分： {{ data.averageScore.toFixed(2) }}分</span></p>
    </div>
    <a-list :data-source="data.scoreDetails" :style="{ backgroundColor: data.scoreDetails.length > 0 ? '#fff' : '' }" style="margin-top: 24px;">
      <a-list-item slot="renderItem" slot-scope="item" style="padding: 20px 14px 16px;">
        <span slot="actions" style="font-size: 20px;">
          <span style="color: #000; font-weight: 700;">{{ item.score.toFixed(2) }}分</span>
          <a-dropdown>
            <a style="margin-left: 6px; font-size: 16px;" class="ant-dropdown-link" @click="e => e.preventDefault()">
              <a-icon type="down" />
            </a>
            <a-menu slot="overlay">
              <a-menu-item @click="route2Detail(item.contestantId)">
                <a href="javascript:;"><a-icon type="bar-chart" /> 详情</a>
              </a-menu-item>
              <a-menu-item @click="delScore(item.contestantId)">
                <a style="color: #f00;" href="javascript:;"><a-icon type="delete" /> 删除</a>
              </a-menu-item>
            </a-menu>
          </a-dropdown>
        </span>
        <a-list-item-meta>
          <h2 slot="title" style="font-weight: 700;">{{ item.contestantName }}</h2>
          <div slot="description">
            <p style="color: blue; margin-bottom: 0; font-size: 14px;">权重分数：{{ item.weightedScore.toFixed(2)}}分</p>
            <p style="margin-bottom: 0; font-size: 14px;">提交时间： {{ item.scoreTime | time }}</p>
          </div>
        </a-list-item-meta>
      </a-list-item>
    </a-list>
  </div>
</template>
<script>
import { getJudgeScoreStatistics, deleteJudgeScore } from '@/api/scoreRecord'
export default {
  data() {
    return {
      data: {
        ratedContestantsCount: 0,
        scoreDetails: [],
      },
      loading: false,
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    loadData() {
      getJudgeScoreStatistics(this.$route.params.id, this.$route.query.judgeId).then(res => {
        this.data = res
      })
    },
    route2Detail(cid) {
      this.$router.push({
        name: 'contestantVoteDataDetail',
        params: {
          judgeId: this.$route.query.judgeId,
          cid: cid,
        },
      })
    },
    delScore(cid) {
      const beforeClose = (action, done) => {
        if (action === 'confirm') {
          deleteJudgeScore(cid, this.$route.query.judgeId).then(res => {
            this.$message.success(res ? '删除成功' : '删除失败')
            this.loadData()
            done()
          })
        } else {
          done()
        }
      }
      this.$dialog.confirm({
        title: '是否确认删除？',
        confirmButtonText: '是',
        cancelButtonText: '否',
        beforeClose,
      }).catch(() => {})
    },
  },
}
</script>
